/*!50003 CREATE*/ /*!50017 DEFINER=`localhost`@`localhost`*/ /*!50003 TRIGGER karnaverde_esther_pruebas.trigger_192_168_1_11_7
   AFTER UPDATE ON karnaverde_esther_pruebas._192_168_1_11_7
   FOR EACH ROW
   BEGIN

   DECLARE v_valor text;

   DECLARE v_min_general_actual text;
   DECLARE v_max_general_actual text;
   DECLARE v_min_general_nueva text;
   DECLARE v_max_general_nueva text;

