   DECLARE v_max_anio_actual text;
   DECLARE v_min_anio_nueva text;
   DECLARE v_max_anio_nueva text;

   DECLARE v_min_mes_actual text;
   DECLARE v_max_mes_actual text;
   DECLARE v_min_mes_nueva text;
   DECLARE v_max_mes_nueva text;

   DECLARE v_min_dia_actual text;
   DECLARE v_max_dia_actual text;
   DECLARE v_min_dia_nueva text;
   DECLARE v_max_dia_nueva text;

   DECLARE v_min_hora_actual text;
   DECLARE v_max_hora_actual text;
   DECLARE v_min_hora_nueva text;
   DECLARE v_max_hora_nueva text;

   DECLARE v_media_general_actual text;
   DECLARE v_media_general_nueva text;

   DECLARE v_media_anio_actual text;
   DECLARE v_media_anio_nueva text;

   DECLARE v_media_mes_actual text;
   DECLARE v_media_mes_nueva text;

   SELECT CAST(REPLACE(valor,',','.') as DECIMAL(4,2))
   INTO v_valor
   FROM karnaverde_esther_pruebas._192_168_1_11_7
   WHERE tipotcaso='estado';

   INSERT INTO karnaverde_esther_pruebas._192_168_1_11_7_historicos(fecha, valor, tipotcaso)
   VALUES(now(), v_valor, 'historico');

   /*
   * MIN MAX GENERAL
   */

   -- MINIMO

   SELECT MIN(CAST(REPLACE(valor,',','.') as DECIMAL(4,2)))
   INTO v_min_general_nueva
   FROM karnaverde_esther_pruebas._192_168_1_11_7_historicos
   WHERE tipotcaso='historico';

   SELECT valor
   INTO v_min_general_actual
   FROM karnaverde_esther_pruebas._192_168_1_11_7_historicos
   WHERE tipotcaso = 'mingeneral';

   IF v_min_general_actual IS NULL THEN
   INSERT INTO karnaverde_esther_pruebas._192_168_1_11_7_historicos(fecha, valor, tipotcaso)
   VALUES (now(), v_min_general_nueva, 'mingeneral');
   ELSE
   UPDATE karnaverde_esther_pruebas._192_168_1_11_7_historicos SET fecha = now(), valor = v_min_general_nueva
   WHERE tipotcaso = 'mingeneral';
   END IF;

   -- MAXIMO

   SELECT MAX(CAST(REPLACE(valor,',','.') as DECIMAL(4,2)))
   INTO v_max_general_nueva
   FROM karnaverde_esther_pruebas._192_168_1_11_7_historicos
   WHERE tipotcaso='historico';

   SELECT valor
   INTO v_max_general_actual
   FROM karnaverde_esther_pruebas._192_168_1_11_7_historicos
   WHERE tipotcaso = 'maxgeneral';

